var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 전화를 받지 않는다고요?","JPN":"シエルさんが電話に出ないですって？","ENG":"Ciel's not answering her phone?","TWN":"你說希爾同學都沒接電話嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼! 수업에는 나오지 않고 이 관심종자가 전화는 몇 통이나 걸었는데도 받지 않았어.","JPN":"そうよ！　授業にも来なかったし、常に他人に矢印を向けているはずなのに、いくら電話しても出ないの。","ENG":"Yeah! She skipped class, and she won't answer the phone no matter how many times I try calling this attention seeker!","TWN":"對啊！她沒來上課，打了好幾通電話也沒接。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무단결석에 학생회 임원의 호출 무시. 이 정도면 징계위원회 감이라고 봐도 되겠지?","JPN":"無断欠席に、生徒会役員からの呼び出しも無視。これって懲戒処分が下ってもおかしくないわよね？","ENG":"Skipping class and ignoring the Student Council's calls. Isn't this enough to try her on the disciplinary committee?","TWN":"她無故曠課，又無視學生會幹部的來電，這樣應該要送懲戒委員會吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 호출한 적 없어. 네가 내 휴대폰을 멋대로 썼을 뿐이잖아.","JPN":"あたしは呼び出しなんかしてないよ。あなたが勝手にあたしの携帯を使ったんでしょ。","ENG":"I never called her. You took my phone and used it without my permission.","TWN":"我又沒有打給她，是你硬拿我的電話打給她的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…이해했습니다.","JPN":"……状況は理解しました。","ENG":"...Understood.","TWN":"…我明白了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇다면 지금 시엘 양의 행방을 아는 사람은 아무도 없다는 거군요.","JPN":"つまり今、シエルさんがどこにいるか知っている人は、誰もいないってことですよね。","ENG":"So no one knows Ciel's whereabouts right now.","TWN":"意思就是現在沒有人知道希爾同學的下落是嗎。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 학생회장님이 직접 찾으러 가시게요?","JPN":"あらら？　生徒会長が直接探しに行かれるんですか？","ENG":"Huh? Are you going to go look for her yourself, Ms. President?","TWN":"嗯？學生會長要親自去找人嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 저녁은 함께 먹기로 약속했거든요.","JPN":"ええ、今日は一緒に夕飯を食べる約束をしているので。","ENG":"Yes. We made plans to have dinner together.","TWN":"對，我們有約好要一起吃晚餐。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"굳이 찾을 필요도 없어.","JPN":"わざわざ探すまでもないわ。","ENG":"You don't need to go looking for her.","TWN":"不用找啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"또 배가 아프다는 핑계로 화장실에 있거나, 벤치에 널브러져서 낮잠 자고 있겠지.","JPN":"どうせまたお腹痛いとか言ってトイレに閉じこもっているか、ベンチでだらしなく昼寝でもしてるんだから。","ENG":"I figure she's in the restroom with some bogus stomachache or napping on a bench somewhere.","TWN":"我看她不是又假裝肚子痛在廁所混，就是躺在長椅上睡覺吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"놀라울 정도로 예전의 나이엘과 비슷하잖아?","JPN":"それ、昔のナイエルちゃんとそっくりだね！","ENG":"That sounds just like the old Naielle.","TWN":"這不就是以前的奈爾嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시끄러! 안 그러거든?! 요즘은.","JPN":"うるさいわよ！　最近は真面目にやってるじゃない！","ENG":"Shut it! I don't do that! Well, not anymore, at least!","TWN":"你閉嘴！我才沒有？！最近啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 시엘에게 라이벌 의식을 갖고 뭐든 열심히 하려는 나이엘의 모습! 보기 좋더라!","JPN":"うん！　シエルちゃんにライバル意識を持ってから何でも頑張って取り組むようになったナイエルちゃんは、とても素敵だよ！","ENG":"Yup! It's really nice to see you work hard with Ciel being your rival and all!","TWN":"嗯！你最近很努力，因為你不想輸給你的假想敵希爾！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"우, 웃기시네! 누가 그런 열등생을 라이벌로 생각한다는 거야!","JPN":"ふ、ふざけないで！　あんな劣等性、ライバルでもなんでもないわよ！","ENG":"A-as if! Who'd think of a loser like that as a rival?!","TWN":"笑，笑死人！誰把那個劣等生當成假想敵啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양.","JPN":"ナイエルさん。","ENG":"Naielle.","TWN":"奈爾同學。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 우리 아카데미에 온 목적을 기억하고 있나요?","JPN":"シエルさんがこのアカデミーに来た目的、覚えていますか？","ENG":"Do you remember for what purpose Ciel enrolled in the Academy?","TWN":"你們還記得希爾同學來學院的目的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미에 온 목적…? 그야 무슨 고향의 전통 때문에 자길 이긴 상대랑 결혼을 한다고…","JPN":"アカデミーに来た目的……？　故郷のしたきりがあって、それで自分に勝利した相手と結婚するとかって……","ENG":"Her purpose...? It was, something about finding a suitable marriage partner...?","TWN":"來學院的目的…？不就是什麼按照老家的傳統要跟打贏自己的人結婚嗎…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"결혼을…?","JPN":"結婚……？","ENG":"Marriage...?","TWN":"結婚…？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"낭자의 이상형은 어떤 사람이오?","JPN":"貴殿のタイプとはどのような人ですか？","ENG":"What is your ideal type of person?","TWN":"敢問姑娘的菜是什麼樣的人？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"푸후웁…!","JPN":"ぷふうっ……！","ENG":"Pfft...!","TWN":"噗噗噗…！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_WATER_03"},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 뭐야? 그 느닷없고 의미심장한 멘트는?!","JPN":"な、何よ？　急にその意味深なセリフ！？","ENG":"W-what? Why are you suddenly asking me that?!","TWN":"什，什麼意思？突然要跟我談心嗎？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"별 의미는 없소.","JPN":"特に意味はありません。","ENG":"There is no reason in particular.","TWN":"沒什麼意思。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그저, 낭자 같은 보통의 여성은 어떤 사람에게 마음이 움직이는지 궁금했다오.","JPN":"ただ、貴殿のような普通の女性はどのような人に心が動くのか気になったのです。","ENG":"I merely wanted to know what kind of person a normal maiden like you would be attracted to.","TWN":"只是好奇，像姑娘這種普通女子會把心交給什麼樣的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐. 뭔가 앞뒤가 안 맞지 않나?","JPN":"待って。なんかそれって話の前後が合ってなくない？","ENG":"Wait. Something doesn't seem to fit, though.","TWN":"等等，怎麼好像哪裡怪怪的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어차피 자기보다 강한 사람과 결혼할 건데, 남의 이상형 같은 건 왜 물어본 거지?","JPN":"どうせ自分より強い人と結婚するのは決まっているのに、何で人のタイプなんて聞いたんだろう？","ENG":"If she's looking for someone stronger than her to marry, why would she ask about my ideal type?","TWN":"既然都要和比自己強的人結婚，那她幹嘛要問我的菜？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 학교에서 보이지 않는 건, 아마도 그 목적과 관련이 있을 가능성이 큽니다.","JPN":"シエルさんが学校からいなくなったのは、その目的と関係している可能性が大きいです。","ENG":"It is very likely that her disappearance from the Academy has to do with her objective.","TWN":"希爾同學之所以會不在學校，應該和那個目的有很大的關係。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 연락이 되지 않는다는 건, 원치 않았던 상황에 직면했을 수도 있다는 뜻이죠.","JPN":"そして連絡がつかないということは、何か望ましくない状況に陥っているということなのでしょう。","ENG":"And, not being able to reach her could mean that she is in an unwanted situation.","TWN":"然而現在聯絡不上她，就表示她很可能正處在不樂見的情況裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"원치 않아……?","JPN":"望ましくない状況……？","ENG":"An unwanted situation...?","TWN":"不樂見……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아앗…?! 그럼 그 녀석 지금 설마?!","JPN":"あ……！？　じゃああいつって今まさか！？","ENG":"Huh...?! Does that mean she's...!?","TWN":"啊啊…？！她該不會？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하. 그렇게 만신창이가 되어서도 눈 하나 깜짝 안 하는 거야?","JPN":"はは。そこまで満身創痍になっているのに、表情一つ変えないとはな？","ENG":"It's incredible that you don't even flinch despite taking such severe damage.","TWN":"哈哈，傷成這樣眼睛連眨都不眨一下嗎？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"경이로운 인내심이네.","JPN":"その忍耐力には感心するぜ。","ENG":"I applaud your patience.","TWN":"真是令人敬佩的忍耐力。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"왜 버티는 거야? 어차피 움직이지 못하면 넌 날 이길 방법이 없을 텐데?","JPN":"どうして降伏しないんだ？　動けない以上、どうせお前に俺は倒せないだろう？","ENG":"But why are you holding on? You can't defeat me if you can't move, no?","TWN":"你在堅持什麼呢？你現在又不能動，那要怎麼打贏我？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"길거리에서 노숙하던 본인을 찾아내고 납치한 것은, 그대의 정보력이 뛰어났기 때문이오.","JPN":"街のホームレスだった自分を見つけ出し、拉致できたのは、貴殿の情報力が優れていたからです。","ENG":"You were able to find and kidnap me while I was sleeping on the streets due to your intelligence.","TWN":"綁架在街頭露宿的在下，是因為你的情報力很卓越。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"대련 중에 본인을 노리고 저격한 것도 상대의 방심을 노린 정당한 기습이었소.","JPN":"訓練の途中、自分を狙って狙撃してきたのは、相手の油断を狙うという至極真っ当な奇襲でした。","ENG":"Your gunshot was a fair ambush that took advantage of the fact that I was distracted by my sparring opponent.","TWN":"在練習中瞄準在下進行狙擊，是趁對方放鬆時突襲，所以是合理的。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"머릿수로 우위를 점하고 싸우는 것 또한 그대가 졸들을 부릴 능력이 있기 때문이오.","JPN":"戦闘において人員の数で優位に立てたのも、貴殿に部下を率いる能力があるからこそ。","ENG":"Having the upper hand in battle by outnumbering me is because you are a capable leader.","TWN":"以人數取得優勢，就表示你很有操弄人的能力。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"허나…","JPN":"ですが……","ENG":"However...","TWN":"但是…"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"절박한 상황에 처한 타인을 이용하고, 손쉽게 버리는 자를… 백서의 문주로 인정하고 싶지는 않소.","JPN":"絶望的な状況の相手を利用し、容易く見捨てる貴殿のような者を……白西の首長として認めたくはありません。","ENG":"You manipulate others who are desperate and discard them like trash... I do not want to admit someone like that to be the leader of White West.","TWN":"將落難的人利用完後便棄之如敝屣…在下不想承認這種人是白西的幫主。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하고 싶지 않다? 그건 섭리음양의 규칙이 아니라 네 의사일 뿐인 것 같은데?","JPN":"認めたくない？　それは燮理陰陽のルールではなく、お前の勝手な意思じゃないか。","ENG":"You don't want to? That doesn't sound like the laws of the balance of yin and yang, but rather your personal opinion.","TWN":"你不想？這似乎不符合燮理陰陽的規矩，單純是你個人的意思吧？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"백서의 도전자는 수단과 방법을 가리지 않고 널 이긴다. 그게 법칙이잖아?","JPN":"白西の挑戦者は手段とやり方を問わず、お前に勝つ。それがルールだろう？","ENG":"Challengers of White West can use any means necessary to win. That's the rule, isn't it?","TWN":"規則不是白西的挑戰者不管用什麼方法都行，只要能贏你就好嗎？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너도 보통의 여자애거든? 자기 취향 정돈 스스로 생각하지 그래?","JPN":"は？　あんたも普通の女の子だけど？　自分の好みくらい自分で考えたら？","ENG":"Huh? You're also a \\"normal maiden!\\" Why don't you find out your own tastes yourself?","TWN":"蛤？你自己還不是普通女子！問你自己就好啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"비겁하고 제멋대로인 무뢰한은… 본인의 이상형이 아니라오.","JPN":"卑怯で自己中心的な荒くれ者は……自分のタイプではありません。","ENG":"A cowardly, arbitrary, and shameless person like you... is not my ideal type.","TWN":"胡作非為的卑鄙無賴…並非在下的菜。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하… 이상형이라-","JPN":"はは……タイプか。","ENG":"Haha... Ideal type, you say...","TWN":"哈哈…你的菜嗎？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"내가 고지식한 문주님께 괜한 걸 가르쳐드린 모양이네.","JPN":"これは、頭でっかちなお前に、余計なことを吹き込んだ奴がいるようだな。","ENG":"I guess I taught our stubborn sect leader of Black East something she didn't need to know.","TWN":"我當初不該跟死腦筋的你說這麼多的。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"알겠어. 설득은 실패한 것 같으니, 연구실에서 뇌부터 손을 봐야겠군.","JPN":"わかった。説得は無理なようだし、研究室に連れて帰って、とりあえず脳に改良を加えないとな。","ENG":"All right. Persuasion seems to be out of the picture now. What's left is to fix you up in our lab, starting with that brain of yours.","TWN":"好吧，既然說服失敗，那之後到研究室就先從洗腦開始吧。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"부디- 내가 개발한 특제 약품들에는 내성이 없길 바랄게. 흑동의 혈귀.","JPN":"くれぐれも、僕が開発した特性薬品に対する耐性がないことを願っているぜ。黒東の吸血鬼。","ENG":"I just hope that you don't have tolerance to any of my specially developed drugs... Bloodseeker of Black East.","TWN":"我希望，你能夠承受得住我開發的特效藥，黑東的血鬼。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어째서 그대는… 지금 가진 힘에 만족하지 못하고 이런 만행을 벌이는 거요?","JPN":"どうして貴殿は……力があるのに、それに満足できず、こんな酷い真似をするのです？","ENG":"How is it that... you are not satisfied with the power that you already possess and are committing this atrocity?","TWN":"為什麼…你現在所擁有的力量無法滿足你嗎？為什麼還要做出這種事？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"잡고 싶은 괴물이 있거든.","JPN":"捕まえたい怪物がいるんだ。","ENG":"Because there is a monster I want to catch.","TWN":"因為有一個我想逮到的怪物。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그래서 나도 수단을 가리지 않기로 했을 뿐이야.","JPN":"だから僕も手段を選ばないことにした。","ENG":"That's why I decided not to be bound by rules.","TWN":"所以我也只是決定要不擇手段而已。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"구룡왕을 죽음 직전까지 내몰았던 네 힘이라면… 그만한 가치가 있을 테니까.","JPN":"九龍王を死の縁まで追い込んだお前の力には……そうするだけの価値があるだろうから。","ENG":"And it'll be all worth it... to have your powers that almost ended the life of the Kowloon King.","TWN":"若你能夠將九龍王逼到絕境…那你的能力或許利用的價值。"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가… 그 일을 어떻게 아는…?","JPN":"貴殿……なぜそのことを……？","ENG":"How... do you know about tha–","TWN":"你…怎麼會知道…？"},"stage":{"bg":"CLAN_002","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"설득치고는 너무 거칠군, 부사관.","JPN":"説得にしては手荒だな、下士官。","ENG":"Sergeant, don't you think you're being a bit rough with your persuasion?","TWN":"你的說服手法還真是粗暴，副官。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"기절시켰을 뿐입니다. 마취가 듣지 않는 체질이니, 이렇게 해서라도 연구소로 끌고 가야죠.","JPN":"気絶させただけです。麻酔は効かない体質ですから、研究所に連れて行くためにはやむを得ません。","ENG":"I just knocked her out. She's immune to tranquilizers, and I have to get her to the lab somehow, right?","TWN":"我只是把她弄暈而已，誰叫麻醉藥對她無效，所以就算這麼做也必須把她弄到研究室。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"그 녀석 때문에 입은 병력손실이 크다. 그렇게 다루다 죽어버리면 곤란해.","JPN":"そいつのせいで多くの兵士を失った。あまり手荒に扱って死なせてくれるなよ。","ENG":"We lost a lot of men because of her. If she dies because of what you did, it puts all of us in a tough spot.","TWN":"她害我們損失這麼多兵力，要是被你弄到沒命的話，我可是會很傷腦筋的。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"약속의 땅을 위해서라면, 저희에겐 우수한 실험체 하나가 졸개 수백 명보다 훨씬 중요하지 않습니까?","JPN":"約束の地のためを考えたら、我々にとっては兵士数百人の命より、優秀な実験体一匹の方がずっと大事なのではないでしょうか？","ENG":"If it's for the promised land, won't an excellent test subject be more important than hundreds of pawns?","TWN":"我們的目的是應許之地，對我們而言，一個好的實驗體，比幾百個小卒重要吧？"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"그 우수한 실험체도 시체가 되어 버리면 쓸모가 없어지지.","JPN":"いくら優秀な実験体でも、死体になったら何の役にも立たないだろう。","ENG":"Even an excellent test subject is useless when it's dead.","TWN":"實驗體若是變成屍體，再優秀也沒用。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"조직이 네 연구를 지원하는 건 그 쓸 만한 실험체들을 선별하는 재주 때문일 뿐이라는 걸 명심해라.","JPN":"組織が貴様の研究を支援しているのは、実験体が使えるものか見定めるその能力あってのことだということを肝に銘じておけ。","ENG":"The organization only supports your research because of your talent to pick out the best test subjects. Don't forget that.","TWN":"你要記住，組織之所以會支持你的研究，只是因為你很會挑實驗體。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"명심하고 있겠습니다.","JPN":"そうですね。","ENG":"I'll keep that in mind.","TWN":"我一直銘記在心。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"지휘관님. 수송선이 도착했습니다.","JPN":"指揮官。輸送船が到着しました。","ENG":"Commander. Our ship has arrived.","TWN":"指揮官，運輸船已抵達。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"실험체들을 전부 화물칸에 실어라.","JPN":"実験体は全て貨物室に積め。","ENG":"Put all the test subjects in the cargo bay.","TWN":"將實驗體全部裝到貨櫃裡。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes, sir.","TWN":"是。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"큭… 이거 놔.","JPN":"くっ……放せ。","ENG":"Kgh... Let go of me.","TWN":"呃…放開我。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"으으… 몸이… 안 움직여.","JPN":"ううっ……身体が……動かねえ。","ENG":"Ngh... I can't... move.","TWN":"呃呃…我的身體…不能動。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"누가… 좀…","JPN":"誰……か……","ENG":"Somebody... please...","TWN":"誰來…幫…"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"무슨 소리지?","JPN":"これは何の音だ？","ENG":"What's that sound?","TWN":"什麼聲音？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"막아 둔 출입문이… 부서지고 있어?","JPN":"封鎖した入口が……壊されている？","ENG":"The door we blocked off... Someone's breaking it!","TWN":"門原本不是堵住的嗎…現在有人正闖進來？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어이! 카운터 아카데미의 최강 엘리트 나이엘 블루스틸님 행차시다!","JPN":"よーし！　カウンターアカデミー最強のエリート、ナイエル・ブルースチール様の御出ましよ！","ENG":"Hey! Counter Academy's elite, Naielle Bluesteel, is here!","TWN":"喂！制裁者學院最強菁英，奈爾‧布魯斯提爾駕到！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시엘 녀석이랑 억지로 결혼하려는 변태 자식이 누군진 몰라도, 아카데미 학생들을 멋대로 납치한 이상 전부 무릎 꿇을 준비나 하시지!","JPN":"シエルと無理やり結婚しようとしてる変態野郎がどこのどいつかは知らないけど、アカデミーの生徒を勝手に拉致してくれたあんたたちは全員打ちのめしてやるわ、覚悟しなさい！","ENG":"I dunno what kind of pervert is forcing Ciel to marry him, but get ready to pay for your crimes of kidnapping an Academy student!","TWN":"雖然不知道是哪個變態要強行跟希爾結婚，但你們竟敢綁架學院的學生，都給我準備下跪求饒吧！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"나이엘…?","JPN":"ナイエル……？","ENG":"Naielle...?","TWN":"奈爾…？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"결혼이라고…?","JPN":"結婚だと……？","ENG":"Marry...?","TWN":"結婚…？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이 바보야! 수상하게 생긴 아저씨들한테 당당하게 소속이랑 이름 밝히지 마!","JPN":"このバカ！　見るからに怪しいおじさんたちに堂々と自分の所属と実名を言ってどうするの！","ENG":"You idiot! Why would you tell these suspicious men your name and affiliation?!","TWN":"你這個傻瓜！你沒看到這些大叔都一副凶神惡煞的樣子嗎？怎麼可以隨便報上自己的名號！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 뭐야? 저 가면 쓴 남자? 딱 봐도 변태 같은데?","JPN":"ふん、何なの？　あのお面の男、どっからどう見ても変態じゃない！","ENG":"Hmph! Oh, that masked guy! You can just tell that he's a pervert.","TWN":"哼，你說那個戴面具的男的嗎？他臉上就寫著變態二個字！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"거기 너! 네 녀석이 강제로 결혼하려고 시엘을 납치한 거지?!","JPN":"ちょっと、そこのあんた！　シエルと無理やり結婚しようと拉致したのってあんたでしょ！？","ENG":"Hey, you! You're the one who kidnapped Ciel to force her to marry you, right?!","TWN":"那邊那個誰！就是你綁架希爾要逼她跟你結婚對吧？！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"이 꼬맹이가 누구더러 변태라는 거야!","JPN":"誰が変態だ、このガキが！","ENG":"Who's this kid calling a pervert, huh?!","TWN":"你這小鬼竟然說我是變態！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"뭣들 하고 있어! 처리해!","JPN":"なにやってんだ！　全員始末しろ！","ENG":"What are you all doing?! Get rid of her!","TWN":"你們看戲啊！還不動手！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 뭐야! 아직 말하고 있는데 다짜고짜 총질이라고?!","JPN":"な、何？　まだ言い終わっていないのに、いきなり撃ってくるなんてアリなの！？","ENG":"W-what?! I'm not done talking! You can't just start shooting me!","TWN":"可惡！怎麼可以趁人家說話的時候開槍！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"아카데미의 학생들이네요. 고등급 카운터라서 쉽게 제압하긴 힘들 겁니다.","JPN":"アカデミーの生徒たちですね。ハイランクのカウンターですから、そう簡単には制圧できないでしょう。","ENG":"They are from the Academy. She is a high-grade Counter, so it won't be easy taking her down.","TWN":"她們是學院的學生，是高階制裁者，應該不好對付。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"저것들이 어떻게 여길 알고 온 거지? 설마 미행이 있었나?","JPN":"あいつらがどうやってここを嗅ぎつけたんだ？　まさか尾行してたのか？","ENG":"How did they know where to find us? Did they follow us here?","TWN":"她們怎麼會知道這個地方？難道有人跟蹤我們？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"얻을 건 얻었으니, 파리가 더 꼬이기 전에 빠지는 편이 좋지 않을까요?","JPN":"目的は全て達成したんですし、これ以上邪魔者が増える前に、この場を離れた方がいいんじゃないでしょうか？","ENG":"We got what we came here for, so I suggest we leave before more unwanted guests arrive.","TWN":"既然已經拿到我們想要的東西，就不需要再跟她們糾纏下去，還是趕快離開這裡吧？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"크윽…","JPN":"くうっ……","ENG":"Krgh...","TWN":"嗯嗯…"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"자료를 처리하는 동안 특조병들은 저 꼬맹이들을 막아라.","JPN":"資料を処理している間、特造兵たちはあのガキどもを食い止めておけ。","ENG":"Send out the special unit to stop her while I take care of the documents.","TWN":"處理資料期間，特務兵負責阻止那些小鬼！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"운반팀은 확보한 실험체들을 데리고 실험실로 철수하도록.","JPN":"運搬チームは確保した実験体を連れて、実験室に撤退しろ。","ENG":"Transport team, retreat to the lab and take the secured test subjects with you.","TWN":"搬運組的人帶著實驗體撤退到實驗室！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Yes, sir!","TWN":"是！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으윽, 그 불량배들과 싸울 때랑 분위기가 좀 다른데? 수도 훨씬 많고.","JPN":"ううっ、あの不良たちと戦ったときとは、雰囲気が全然違うと思わない……？　数もずっと多いし。","ENG":"Ngh, it feels different from when I fought those bullies. Plus, there are a lot more of them.","TWN":"可惡，和那些壞蛋交手時感覺不太一樣，而且他們人數好多！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"겁먹지 마! 넌 관리국이 공인한 A급 카운터잖아!","JPN":"怯まないで！　あなたは管理局公認のA級カウンターでしょ！？","ENG":"Don't be intimidated! You're a Grade A Counter officialized by the Administration!","TWN":"別怕！你可是管理局鑑定的A級制裁者！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그… 그렇지! 초엘리트인 이 몸이 고작 이런 녀석들에게 쫄 리가…!","JPN":"そ、そうね！　超エリートの私が、たかがこんなやつらに怯むわけ……！","ENG":"Th-that's right! There's no way a super-elite like me is afraid of these scum...!","TWN":"對…對啊！我可是超級菁英，有什麼理由怕他們…！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"상대는 카운터다! 봐주지 말고 쏴!","JPN":"相手はカウンターだ！　手加減なしで撃て！","ENG":"She's a Counter! Shoot her until she's Swiss cheese!","TWN":"對方可是制裁者！不要手下留情，開槍！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"히익! 잠깐! 아직 마음의 준비가…!","JPN":"ひいっ！　待って！　まだ心の準備が……！","ENG":"Eek! Time out! I'm not ready...!","TWN":"嗚！等一下！人家還沒有心理準備啦…！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"뭣…?! 총이 반으로 갈라졌어?","JPN":"なっ……！？　銃が真っ二つに……？","ENG":"Huh...?! My gun just split in half!","TWN":"什麼…？！槍裂成二半？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제 앞에서 살생은 금지입니다.","JPN":"私の目の前で殺生は許しません。","ENG":"No killing shall be done on my watch.","TWN":"禁止在我面前殺生。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"역시 학생회장님! 보초들을 벌써 모조리 도륙내 버리고 오셨군요!","JPN":"さすが生徒会長！　もう見張りたちを片っ端から切り刻んだんですね！","ENG":"Ms. President!! You've already sliced your way through the guards!","TWN":"真不愧是學生會長！瞬間就把步兵殺個精光！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"도륙내진 않았어요. 제압했을 뿐.","JPN":"切り刻んではいません。制圧しただけですよ。","ENG":"I did not slice them. I merely apprehended them.","TWN":"我沒有殺他們，只是制伏他們而已。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"윽…! 또 방심했다가 활약할 기회를 놓치다니!","JPN":"うっ……！　また油断して、活躍のチャンスを奪われてしまった！","ENG":"Ngh...! I lost my chance to be the star again!","TWN":"唔…！我又太大意失去出風頭的機會！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘은 어떻게 됐죠?","JPN":"シエルさんはどうなりましたか？","ENG":"What happened to Ciel?","TWN":"希爾人呢？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"붙잡혀 있는 건 확인했지만… 금방 다른 곳으로 끌려갔어요!","JPN":"さっき捕まっているのは確認したんですが……すぐどこかに連れていかれてしまって！","ENG":"I know she's being held captive... But they took her way just now!","TWN":"她確實是被抓到這裡來…但剛才又被送到其他地方！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어그로와 블로킹, 그 두 녀석도 같이 잡혀 있었어!","JPN":"アグロとブロッキング、その二人も一緒に捕まっていたよ！","ENG":"Aggro and Block are also with her!","TWN":"阿格洛和布洛京，他們也一起被抓去！"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"...Understood.","TWN":"…明白。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금부터는 저도 가세하도록 하죠.","JPN":"ここからは私も加勢します。","ENG":"I shall assist you from here.","TWN":"接下來我也會加入你們。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"아카데미의 카운터라면 기껏해야 등급만 높은 풋내기들일 텐데…","JPN":"アカデミーのカウンターなんざ、せいぜいランクが高いだけの青二才ばかりなはずだが……","ENG":"All Academy Counters are just punks with high Counter grades...","TWN":"學院的制裁者就算等級再高，也只是初出茅廬的小鬼吧…"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"대체 그 실력은 뭐지? 네놈은 정체가 뭐냐?","JPN":"いったいその実力は何だ？　貴様は何者だ？","ENG":"But you're different. Who are you?","TWN":"但怎麼這麼厲害？你們到底是誰？"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그런 건 알 필요 없습니다.","JPN":"あなたにそれを教える義理はありません。","ENG":"I have no obligation to introduce myself to you.","TWN":"這你不需要知道。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저희는 당신들이 멋대로 납치한 학생들을 데리러 왔을 뿐이니까요.","JPN":"私たちはあなたたちが攫った生徒たちを連れ戻しにきただけですから。","ENG":"I am only here to retrieve the students you have kidnapped.","TWN":"我們是來把被你們綁架的學生帶回去的。"},"stage":{"bg":"HALL","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};